parameters.command:
export TZ=America/Phoenix
mkdir -p /home/node/kazm-tape
DATE=$(date +%Y-%m-%d)
HOUR=$(date +%H)
BLOCK=$(( (10#$HOUR/6)*6 ))
BLOCKSTR=$(printf "%02d" $BLOCK)
NAME="lounge-${DATE}-${BLOCKSTR}00.mp3"
FILE="/home/node/kazm-tape/${NAME}"
rm -f "$FILE"

timeout 21600 wget -q -O "$FILE" https://streaming.mellowmountainradio.com/listen/mellowmountainradio/radio.mp3
SIZE=$(wc -c < "$FILE" 2>/dev/null || echo 0)
echo "[tape] captured ${NAME}: ${SIZE} bytes"

if [ "$SIZE" -lt 50000000 ]; then
  echo "[tape] recording too small, skipping upload"
  rm -f "$FILE"
  exit 0
fi

FILE="$FILE" NAME="$NAME" AZKEY="PASTE-YOUR-AZURACAST-API-KEY" node <<'NODEEOF'
const fs = require('fs');
(async () => {
  const path = process.env.FILE;
  const name = process.env.NAME;
  const key = process.env.AZKEY;
  const base = 'https://streaming.mellowmountainradio.com/api/station/mellowmountainradio';
  const buf = fs.readFileSync(path);
  const b64 = buf.toString('base64');
  const createRes = await fetch(base + '/files', {
    method: 'POST',
    headers: { 'X-API-Key': key, 'Content-Type': 'application/json' },
    body: JSON.stringify({ path: 'Archive/' + name, file: b64 }),
  });
  const created = await createRes.json();
  if (!created.id) { console.log('[tape] upload failed', JSON.stringify(created)); process.exit(1); }
  const putRes = await fetch(base + '/file/' + created.id, {
    method: 'PUT',
    headers: { 'X-API-Key': key, 'Content-Type': 'application/json' },
    body: JSON.stringify({ playlists: [{ id: 16 }] }),
  });
  console.log('[tape] published', name, 'as file', created.id, 'assoc status', putRes.status);
})().catch(e => { console.log('[tape] error', String(e)); process.exit(1); });
NODEEOF

rm -f "$FILE"
